    // isFullAnim: true=首次入场动画，false=hover 即时重绘
    drawBoxes(isFullAnim = false) {
      const canvas = this.$refs.boxCanvas;
      const img = this.$refs.baseImg;
      if (!canvas || !img || !this.hasResult) return;
      const boxes = this.result?.boxes ?? [];
      canvas.width = img.clientWidth;
      canvas.height = img.clientHeight;
      const ctx = canvas.getContext('2d');

      // 取消上一次未完成的动画
      if (this._boxAnimFrame) {
        cancelAnimationFrame(this._boxAnimFrame);
        this._boxAnimFrame = null;
      }
      if (!isFullAnim) {
        // hover 重绘：直接画最终态，无需动画
        this._drawFrame(ctx, canvas, boxes, 1);
        return;
      }
      let prog = 0;
      const total = 60;
      const tick = () => {
        prog++;
        const t = Math.min(prog / total, 1);
        this._drawFrame(ctx, canvas, boxes, t);
        if (prog < total) {
          this._boxAnimFrame = requestAnimationFrame(tick);
