      const isN = box.x1 <= 1 && box.y1 <= 1;
      const sw = canvas.width,
        sh = canvas.height;
      const mw = this.imageMeta?.width || 1;
      const mh = this.imageMeta?.height || 1;
      if (isN) return {
        x1: box.x1 * sw,
        y1: box.y1 * sh,
        x2: (box.x1 + box.x2) * sw,
        y2: (box.y1 + box.y2) * sh
