    },
    async deleteFarmById(farmId) {
      const farm = this.farms.find(f => f.id === farmId);
      if (!farm || !confirm(`确定要删除猪场"${farm.name}"吗？`)) return;
      try {
        const response = await deleteFarm(farmId);
        if (response.success) {
          this.farms = this.farms.filter(f => f.id !== farmId);
          if (this.selectedFarmId === farmId) this.selectedFarmId = null;
          this.$store.commit('ADD_LOG', {
            msg: `成功删除猪场：${farm.name}`,
            type: 'success'
          });
        }
      } catch (err) {
        this.$store.commit('ADD_LOG', {
          msg: '删除猪场失败：' + err.message,
          type: 'error'
        });
      }
    },
    formatFarmDate(dateStr) {
      if (!dateStr) return '';
      return new Date(dateStr).toLocaleDateString('zh-CN', {
        year: 'numeric',
        month: '2-digit',
        day: '2-digit'
      });
    }
  }
};
